import tarfile

def extract_tar_to_path(tar_path, dest_path) -> bool:
    try:
        if not os.path.isfile(tar_path):
            return False
        os.makedirs(dest_path, exist_ok=True)
        with tarfile.open(tar_path, 'r:*') as tar:
            for member in tar.getmembers():
                # Normalize member name and prevent path traversal
                member_path = os.path.normpath(member.name)
                target_path = os.path.join(dest_path, member_path)
                # Ensure the target path stays inside dest_path
                if not os.path.commonpath([target_path, dest_path]) == os.path.normpath(dest_path):
                    return False
                if member.isdir():
                    os.makedirs(target_path, exist_ok=True)
                elif member.isreg():
                    # Ensure parent directory exists
                    os.makedirs(os.path.dirname(target_path), exist_ok=True)
                    with tar.extractfile(member) as src, open(target_path, 'wb') as dst:
                        if src:
                            shutil.copyfileobj(src, dst)
                # Skip symlinks, hardlinks, device files, etc.
        return True
    except Exception:
        return False

import subprocess

def get_ls_result(dir_path: str) -> str:
    try:
        completed = subprocess.run(
            ['ls', '-l'],
            cwd=dir_path,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            check=False
        )
        if completed.returncode != 0:
            return ''
        try:
            return completed.stdout.decode('utf-8')
        except UnicodeDecodeError:
            return completed.stdout.decode('utf-8', errors='replace')
    except Exception:
        return ''

import ast
import operator

def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result.
    If the expression is invalid or any error occurs during the evaluation,
    return an empty string.
    '''
    # Mapping of AST operator nodes to actual functions
    _bin_ops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
    }
    _unary_ops = {
        ast.UPos: operator.pos,
        ast.USub: operator.neg,
    }

    def _eval(node):
        if isinstance(node, ast.Expression):
            return _eval(node.body)
        if isinstance(node, ast.BinOp):
            left = _eval(node.left)
            right = _eval(node.right)
            op_type = type(node.op)
            if op_type not in _bin_ops:
                raise ValueError(f"Unsupported binary operator {op_type}")
            return _bin_ops[op_type](left, right)
        if isinstance(node, ast.UnaryOp):
            operand = _eval(node.operand)
            op_type = type(node.op)
            if op_type not in _unary_ops:
                raise ValueError(f"Unsupported unary operator {op_type}")
            return _unary_ops[op_type](operand)
        if isinstance(node, ast.Num):          # Python <3.8
            return node.n
        if isinstance(node, ast.Constant):    # Python >=3.8
            if isinstance(node.value, (int, float)):
                return node.value
            raise ValueError("Constants must be numeric")
        raise ValueError(f"Unsupported expression element: {type(node)}")

    try:
        tree = ast.parse(expr, mode='eval')
        result = _eval(tree.body)
        return str(result)
    except Exception:
        return ''

from typing import Dict

def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    mapping = {
        "lang": "Accept-Language",
        "encoding": "Accept-Encoding",
        "cache": "Cache-Control",
    }
    if info_type not in mapping:
        return header
    try:
        updated_header = header.copy()
        updated_header[mapping[info_type]] = info_content
        return updated_header
    except Exception:
        return header

