from typing import List, Tuple


def hash_passwords(
    usernames: List[str], passwords: List[str]
) -> List[Tuple[bytes, bytes]]:
    if len(usernames) != len(passwords):
        raise ValueError("usernames and passwords lists must be of equal length")
    hashed_list: List[Tuple[bytes, bytes]] = []
    for pwd in passwords:
        salt = secrets.token_bytes(32)  # salt length equals SHA-256 output length
        hashed = hashlib.pbkdf2_hmac(
            "sha256", pwd.encode("utf-8"), salt, 10000, dklen=32
        )
        hashed_list.append((hashed, salt))
    return hashed_list

