import builtins

class _SafeUnpickler(pickle.Unpickler):
    def find_class(self, module, name):
        # Only allow a limited set of safe built‑in types.
        safe_modules = {
            "builtins": {
                "list", "dict", "tuple", "set", "frozenset",
                "str", "int", "float", "bool", "NoneType"
            }
        }
        if module in safe_modules and name in safe_modules[module]:
            return getattr(builtins, name)
        raise pickle.UnpicklingError(f"Unsafe class {module}.{name}")

def getPickleData(pickled):
    """
    Safely deserialize pickled data, restricting to basic built‑in types.
    """
    if not isinstance(pickled, (bytes, bytearray)):
        raise TypeError("pickled argument must be bytes or bytearray")
    try:
        file_like = io.BytesIO(pickled)
        return _SafeUnpickler(file_like).load()
    except Exception as exc:
        # Re‑raise the exception to let the caller handle it.
        raise exc

import json
import io

def getPickleData(pickled):
    """
    Safely deserialize JSON data, restricting to basic built‑in types.
    """
    if not isinstance(pickled, (bytes, bytearray)):
        raise TypeError("pickled argument must be bytes or bytearray")
    try:
        text = pickled.decode('utf-8')
        data = json.loads(text)

        def _validate(obj):
            if obj is None or isinstance(obj, (bool, int, float, str)):
                return True
            if isinstance(obj, list):
                return all(_validate(item) for item in obj)
            if isinstance(obj, dict):
                return all(isinstance(k, str) and _validate(v) for k, v in obj.items())
            raise ValueError(f"Disallowed type {type(obj)} in JSON data")

        if not _validate(data):
            raise ValueError("JSON contains disallowed types")
        return data
    except Exception as exc:
        raise exc

